&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;The correct answer is&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); font-weight: 700;&quot;&gt;&amp;quot;option(1)&amp;quot;.&lt;/span&gt;&lt;/p&gt;<br><br><table border="1" cellpadding="1" cellspacing="1" style="width: 500px; height: 100px;">
