&lt;p style=&quot;margin: 0;&quot;&gt;The logic followed here is:&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 300px; border-collapse: collapse;&quot;&gt;
	&lt;tbody&gt;
